create or replace function public.refresh_commission_preview(p_month date default null, p_store_id uuid default null) returns jsonb language plpgsql security definer set search_path to 'public' as $function$ declare target_month date; sid uuid; v_run_id uuid; base_count integer:=0; unit_count integer:=0; spiff_count integer:=0; trade_spiff_count integer:=0; buy_fee_count integer:=0; flat_adjustment_count integer:=0; pct_adjustment_count integer:=0; begin target_month=date_trunc('month',coalesce(p_month,current_date))::date; sid=p_store_id; if sid is null and public.current_role()='manager' then sid=public.current_store_id(); end if; if exists(select 1 from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status in ('locked','paid')) then raise exception 'Commission run is locked or paid.'; end if; select cr.id into v_run_id from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status='preview' order by cr.refreshed_at desc nulls last,cr.created_at desc,cr.id desc limit 1; if v_run_id is not null then delete from public.commission_lines cl where cl.run_id in (select cr.id from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status='preview' and cr.id<>v_run_id); delete from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status='preview' and cr.id<>v_run_id; update public.commission_runs set refreshed_at=now(),created_by=auth.uid() where id=v_run_id; else insert into public.commission_runs(month,store_id,status,created_by,refreshed_at) values(target_month,sid,'preview',auth.uid(),now()) returning id into v_run_id; end if; delete from public.commission_lines where run_id=v_run_id; with participants as (select d.id deal_id,d.front_gross,d.stock_type,d.make,d.contract_date,d.store_id,d.raw_json,dp.employee_id,dp.split_pct,sum(dp.split_pct) over(partition by dp.employee_id) total_units from public.sales_deals d join public.deal_participants dp on dp.deal_id=d.id where date_trunc('month',d.contract_date)::date=target_month and coalesce(d.make,'')<>'' and coalesce(d.stock_number,'')<>'' and dp.employee_id is not null and (sid is null or d.store_id=sid)), calc as (select p.*,coalesce(pp.base_rate_pct,10) base_rate_pct,coalesce(pp.rate_cap_pct,25) rate_cap_pct,public.unit_rate_enhancement(p.total_units,target_month,p.store_id) unit_rate_pct,public.mini_amount(p.total_units,target_month,p.store_id) mini from participants p left join lateral public.default_pay_plan_for(p.employee_id,target_month) pp on true), amounts as (select *,least(base_rate_pct+unit_rate_pct,rate_cap_pct) total_rate_pct,least(base_rate_pct,least(base_rate_pct+unit_rate_pct,rate_cap_pct)) effective_base_rate_pct,round(case when coalesce(front_gross,0)<0 then 0 else coalesce(front_gross,0)*split_pct*least(base_rate_pct+unit_rate_pct,rate_cap_pct)/100 end,2) total_pct_amount,round(case when coalesce(front_gross,0)<0 then 0 else coalesce(front_gross,0)*split_pct*least(base_rate_pct,least(base_rate_pct+unit_rate_pct,rate_cap_pct))/100 end,2) base_pct_amount,round(mini*split_pct,2) mini_line_amount from calc) insert into public.commission_lines(run_id,employee_id,deal_id,line_type,amount,explanation,source_table,source_id) select v_run_id,employee_id,deal_id,'deal_base',case when mini_line_amount>total_pct_amount then mini_line_amount else base_pct_amount end,case when mini_line_amount>total_pct_amount then concat('Mini ',mini,' beat total percent commission ',total_rate_pct,'%.') else concat('Base ',effective_base_rate_pct,'% of commissionable gross. Total percent check ',total_rate_pct,'%.') end,'sales_deals',deal_id from amounts; get diagnostics base_count=row_count; with participants as (select d.id deal_id,d.front_gross,d.stock_type,d.make,d.contract_date,d.store_id,d.raw_json,dp.employee_id,dp.split_pct,sum(dp.split_pct) over(partition by dp.employee_id) total_units from public.sales_deals d join public.deal_participants dp on dp.deal_id=d.id where date_trunc('month',d.contract_date)::date=target_month and coalesce(d.make,'')<>'' and coalesce(d.stock_number,'')<>'' and dp.employee_id is not null and (sid is null or d.store_id=sid)), calc as (select p.*,coalesce(pp.base_rate_pct,10) base_rate_pct,coalesce(pp.rate_cap_pct,25) rate_cap_pct,public.unit_rate_enhancement(p.total_units,target_month,p.store_id) unit_rate_pct,public.mini_amount(p.total_units,target_month,p.store_id) mini from participants p left join lateral public.default_pay_plan_for(p.employee_id,target_month) pp on true), amounts as (select *,round(case when coalesce(front_gross,0)<0 then 0 else coalesce(front_gross,0)*split_pct*least(base_rate_pct+unit_rate_pct,rate_cap_pct)/100 end,2) total_pct_amount,round(case when coalesce(front_gross,0)<0 then 0 else coalesce(front_gross,0)*split_pct*least(base_rate_pct,least(base_rate_pct+unit_rate_pct,rate_cap_pct))/100 end,2) base_pct_amount,round(mini*split_pct,2) mini_line_amount,greatest(least(base_rate_pct+unit_rate_pct,rate_cap_pct)-least(base_rate_pct,least(base_rate_pct+unit_rate_pct,rate_cap_pct)),0) effective_unit_rate_pct from calc) insert into public.commission_lines(run_id,employee_id,deal_id,line_type,amount,explanation,source_table,source_id) select v_run_id,employee_id,deal_id,'unit_enhancement',total_pct_amount-base_pct_amount,concat('Unit sales commission enhancement ',effective_unit_rate_pct,'%. Rounded as total percent minus base percent.'),'sales_deals',deal_id from amounts where mini_line_amount<=total_pct_amount and total_pct_amount-base_pct_amount<>0; get diagnostics unit_count=row_count; return jsonb_build_object('run_id',v_run_id,'month',target_month,'base_lines',base_count,'unit_enhancement_lines',unit_count,'commission_lines',base_count+unit_count); end; $function$;